#include <stdio.h>

int main(void) {
    int n;
    scanf("%d", &n);

    double sum = 1.0; // Start with the first term 1

    for (int i = 2; i <= n; i++) {
        int numerator = 2 * i + 1;
        int denominator = i * i - 1;
        double term = ((i + 1) % 2 == 0 ? -1 : 1) * (double)numerator / denominator;
        sum += term;
    }

    printf("%.3f\n", sum);

    return 0;
}

#include <stdio.h>

int main(void) {
    int n;
    scanf("%d", &n);

    for (int i = 1; i <= n; i++) {
        for (int j = 0; j < i; j++) {
            printf("%d", i);
        }
        printf("\n");
    }

    for (int i = n - 1; i >= 1; i--) {
        for (int j = 0; j < i; j++) {
            printf("%d", i);
        }
        printf("\n");
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <time.h>

int main(void) {
    srand(time(NULL));
    int numbers[5], position, score = 0;
    char guess;

    // Generate random numbers
    for (int i = 0; i < 5; i++) {
        numbers[i] = rand() % 10 + 1;
    }

    printf("Numbers: ");
    for (int i = 0; i < 5; i++) {
        printf("%d ", numbers[i]);
    }
    printf("\n");

    // Game loop
    for (int i = 0; i < 5; i++) {
        printf("Pick a number and guess if it's even (E) or odd (O): ");
        if (scanf("%d %c", &position, &guess) == 2) {
            if (position >= 1 && position <= 5) {
                int num = numbers[position - 1];
                char correct_guess = (num % 2 == 0) ? 'E' : 'O';
                if (guess == correct_guess) {
                    score += 5;
                    printf("Correct! You win 5 points.\n");
                } else {
                    printf("Wrong! No points this time.\n");
                }
            } else {
                printf("Invalid position. Please enter a number between 1 and 5.\n");
            }
        } else {
            printf("Invalid input. Please enter a number followed by E or O.\n");
        }
    }

    printf("Total win %d points\n", score);
    return 0;
}
